131	/****************************************************************************
132	 * Name: host_gpiochip_irq_request
133	 *
134	 * Input Parameters:
135	 *   priv   - A pointer to instance of Linux gpiochip.
136	 *   pin    - The pin number.
137	 *   cfgset - The config set of the pin.
138	 *
139	 * Returned Value:
140	 *   0 for success, other for fail.
141	 ****************************************************************************/
142	
143	int host_gpiochip_irq_request(struct host_gpiochip_dev *priv, uint8_t pin,
144	                              uint16_t cfg)
145	{
146	  struct gpio_v2_line_request req;
147	  int nonblock = 1;
148	  int ret;
149	
150	  if (priv->line_fd[pin] > 0)
151	    {
152	      close(priv->line_fd[pin]);
153	      priv->line_fd[pin] = -1;
154	    }
155	
156	  memset(&req, 0, sizeof(req));
157	  switch (cfg)
158	    {
159	      case GPIOCHIP_LINE_FLAG_FALLING:
160	        req.config.flags = GPIO_V2_LINE_FLAG_EDGE_FALLING;
161	        break;
162	      case GPIOCHIP_LINE_FLAG_RISING:
163	        req.config.flags = GPIO_V2_LINE_FLAG_EDGE_RISING;
164	        break;
165	      case GPIOCHIP_LINE_FLAG_BOTH:
166	        req.config.flags = GPIO_V2_LINE_FLAG_EDGE_FALLING |
167	                           GPIO_V2_LINE_FLAG_EDGE_RISING;
168	        break;
169	      default:
170	        req.config.flags = 0;
171	        break;
172	    }
173	
174	  req.offsets[0] = pin;
175	  req.num_lines = 1;
176	  req.config.flags |= GPIO_V2_LINE_FLAG_INPUT;
177	  if (req.config.flags != GPIO_V2_LINE_FLAG_INPUT)
178	    {
179	      snprintf(req.consumer, sizeof(req.consumer) - 1, "gpio-irq%d", pin);
180	    }
181	
182	  /* Warn only pin 10 can register in ch341A */
183	
184	  ret = host_uninterruptible(ioctl, priv->file, GPIO_V2_GET_LINE_IOCTL,
185	                             &req);
186	  if (ret < 0)
187	    {
188	      gpioerr("ERROR: ioctl failed: %s \n", strerror(errno));
189	      return -errno;
190	    }
191	
192	  ret = host_uninterruptible(ioctl, req.fd, FIONBIO, &nonblock);
193	  if (ret < 0)
194	    {
195	      gpioerr("ERROR: Failed to set non-blocking: %s\n", strerror(errno));
196	      return -errno;
197	    }
198	
199	  priv->line_fd[pin] = req.fd;
200

  return 0;
}

/****************************************************************************
 * Name: host_gpiochip_writepin
 *
 * Description:
 *   Write gpiochip pin value.
 *
 * Input Parameters:
 *   priv  - A pointer to instance of Linux gpiochip.
 *   pin   - The pin number.
 *   value - The value write to the pin.
 *
 * Returned Value:
 *   0 for success, other for fail.
 ****************************************************************************/

int host_gpiochip_writepin(struct host_gpiochip_dev *priv, uint8_t pin,
                           bool value)
{
  struct gpio_v2_line_values vals;
  int ret;

  if (priv->line_fd[pin] <= 0)
    {
      gpioerr("ERROR: Invalid pin %d config\n", pin);
      return -EINVAL;
    }

  memset(&vals, 0, sizeof(vals));
  vals.mask = 1;
  vals.bits = !!value;

  ret = host_uninterruptible(ioctl, priv->line_fd[pin],
                             GPIO_V2_LINE_SET_VALUES_IOCTL, &vals);
  if (ret < 0)
    {
      gpioerr("ERROR: Failed to set pin %d value %d\n", pin, value);
      return -errno;
    }

  return 0;
}

/****************************************************************************
 * Name: host_gpiochip_readpin
 *
 * Description:
 *   Read gpiochip pin value.

 *   Read gpiochip pin value.
 *
 * Input Parameters:
 *   priv  - A pointer to instance of Linux gpiochip.
 *   pin   - The pin number.
 *   value - The value write to the pin.
 *
 * Returned Value:
 *   0 for success, other for fail.
 ****************************************************************************/

int host_gpiochip_readpin(struct host_gpiochip_dev *priv, uint8_t pin,
                          bool *value)
{
  struct gpio_v2_line_values vals;
  int ret;

  if (priv->line_fd[pin] <= 0)
    {
      gpioerr("ERROR: Invalid pin %d config\n", pin);
      return -EINVAL;
    }

  memset(&vals, 0, sizeof(vals));
  vals.mask = 1;
  ret = host_uninterruptible(ioctl, priv->line_fd[pin],
                             GPIO_V2_LINE_GET_VALUES_IOCTL, &vals);
  if (ret < 0)
    {
      gpioerr("ERROR: Failed to get pin%d value, errno[%d]\n", pin, errno);
      return -errno;
    }

  *value = !!(vals.bits & 0x01);

  return 0;
}

/****************************************************************************
 * Name: host_gpiochip_irq_active
 *
 * Description:
 *   register gpio for gpiochip device
 *
 * Input Parameters:
 *   priv - A pointer to instance of Linux gpiochip.
 *   pin  - gpio pin of Linux gpiochip device.
 *
 * Returned Value:
 *   0 for OK.
 *

 *
 ****************************************************************************/

bool host_gpiochip_irq_active(struct host_gpiochip_dev *priv, uint8_t pin)
{
  if (priv->line_fd[pin] > 0)
    {
      struct gpio_v2_line_event ev;
      int fd = priv->line_fd[pin];
      memset(&ev, 0, sizeof(ev));
      if (host_uninterruptible(read, fd, &ev, sizeof(ev)) == sizeof(ev))
        {
          return true;
        }
    }

  return false;
}

/****************************************************************************
 * Name: host_gpiochip_get_line
 *
 * Description:
 *   Get line info from gpiochip device
 *
 * Input Parameters:
 *   priv  - A pointer to instance of Linux gpiochip.
 *   pin   - gpio line of Linux gpiochip.
 *   input - A pointer to direction of gpioline.
 *
 * Returned Value:
 *   0 for OK.
 *
 ****************************************************************************/

int host_gpiochip_get_line(struct host_gpiochip_dev *priv, uint8_t pin,
                           bool *input)
{
  struct gpio_v2_line_info info;
  int ret;

  memset(&info, 0, sizeof(info));
  info.offset = pin;
  ret = host_uninterruptible(ioctl, priv->file, GPIO_V2_GET_LINEINFO_IOCTL,
                             &info);
  if (ret < 0)
    {
      gpioerr("Failed to get line info: %d", ret);
      return -errno;
    }

  if (info.flags & GPIO_V2_LINE_FLAG_USED)
    {
      return 1;
    }

  if (info.flags & GPIO_V2_LINE_FLAG_OUTPUT)
    {
      *input = false;
    }
  else
    {
      *input = true;
    }

  return 0;
}

/****************************************************************************
 * Name: host_gpiochip_alloc
 *
 * Description:
 *   Initialize one gpiochip device
 *
 * Input Parameters:
 *   filename - the name of gpiochip device in Linux, e.g. "/dev/gpiochipN".
 *
 * Returned Value:
 *   The pointer to the instance of Linux gpiochip device.
 *
 ****************************************************************************/

struct host_gpiochip_dev *host_gpiochip_alloc(const char *filename)
{
  struct host_gpiochip_dev *dev;

  dev = malloc(sizeof(struct host_gpiochip_dev));
  if (!dev)
    {
      gpioerr("Failed to allocate memory for gpiochip device");
      return NULL;
    }

  dev->file = host_uninterruptible(open, filename, O_RDWR | O_CLOEXEC);
  if (dev->file < 0)
    {
      gpioerr("Failed to open %s: %d", filename, dev->file);
      free(dev);
      return NULL;
    }

  return dev;
}

/****************************************************************************
 * Name: host_gpiochip_free
 *
 * Description:
 *   Uninitialize an gpiochip device
 *
 * Returned Value:
 *   None.
 *
 ****************************************************************************/

void host_gpiochip_free(struct host_gpiochip_dev *priv)
{
  host_uninterruptible(close, priv->file);
  free(priv);
}

 *
 * Input Parameters:
 *   dev   - A pointer to instance of sim gpiochip device.
 *   pin   - The pin number.
