<new_str>void host_gpiochip_free(struct host_gpiochip_dev *priv)
{
  int i;

  if (priv)
    {
      /* Close all open line file descriptors */
      for (i = 0; i < CONFIG_IOEXPANDER_NPINS; i++)
        {
          if (priv->line_fd[i] > 0)
            {
              host_uninterruptible(close, priv->line_fd[i]);
              priv->line_fd[i] = -1;
            }
        }

      host_uninterruptible(close, priv->file);
      free(priv);
