    {
      case GPIOCHIP_LINE_FLAG_FALLING:
        req.config.flags = GPIO_V2_LINE_FLAG_EDGE_FALLING;
        break;
      case GPIOCHIP_LINE_FLAG_RISING:
        req.config.flags = GPIO_V2_LINE_FLAG_EDGE_RISING;
        break;
      case GPIOCHIP_LINE_FLAG_BOTH:
        req.config.flags = GPIO_V2_LINE_FLAG_EDGE_FALLING |
