   177	        {
   178	          /* Check if it's already configured for the same interrupt type */
   179	          uint64_t expected_flags = GPIO_V2_LINE_FLAG_INPUT;
   180	          switch (cfg)
   181	            {
   182	              case GPIOCHIP_LINE_FLAG_FALLING:
   183	                expected_flags |= GPIO_V2_LINE_FLAG_EDGE_FALLING;
   184	                break;
   185	              case GPIOCHIP_LINE_FLAG_RISING:
   186	                expected_flags |= GPIO_V2_LINE_FLAG_EDGE_RISING;
   187	                break;
   188	              case GPIOCHIP_LINE_FLAG_BOTH:
